-- ---- Reference -------------------------------------------------------------
create table departments (
  id   text primary key,
  name text not null,
  code text
);

create table centers (
  id       text primary key,
  name     text not null,
  location text
);

create table rooms (
  id          text primary key,
  room_number text,
  capacity    int,
  center_id   text references centers(id)
);

create table courses (
  id            text primary key,
  unit_code     text,
  unit_title    text not null,
  credit_hours  int default 0,
  department_id text references departments(id),
  total_los     int default 0
);

create table users (
  id            text primary key,
  username      text unique not null,
  full_name     text not null,
  email         text,
  role          text not null check (role in ('Admin','Coordinator','Trainer','Trainee')),
  department_id text references departments(id),
  mobile_number text,
  status        text not null default 'Active',
  created_at    text
);

create table trainers (
  id              text primary key,
  user_id         text references users(id),
  name            text not null,
  staff_no        text,
  department_id   text references departments(id),
  employment_type text check (employment_type in ('FT','PT')),
  present_status  text,
  rating          real,
  photo_url       text
);

-- ---- Transactional (created empty; filled with real data via the app) ------
create table trainees (
  id                       text primary key,
  student_id               text unique,
  first_name               text,
  last_name                text,
  full_name                text,
  sex                      text,
  academic_level           text,
  section_code             text,
  department_id            text references departments(id),
  entry_year               text,
  city                     text,
  phone                    text,
  emergency_contact_name   text,
  emergency_contact_phone1 text,
  status                   text default 'Active',
  photo_url                text
);

create table schedules (
  id             text primary key,
  entry_year     text,
  section_code   text,
  course_id      text references courses(id),
  trainer_id     text references trainers(id),
  room_id        text references rooms(id),
  center_id      text references centers(id),
  schedule_time1 text,
  schedule_time2 text,
  start_date     text,
  end_date       text
);

create table attendance (
  id          text primary key,
  schedule_id text references schedules(id),
  trainer_id  text references trainers(id),
  date        text,
  month       text,
  present     int default 0,
  absent      int default 0,
  late        int default 0,
  total       int default 0,
  photo_url   text,
  notes       text
);

create table course_coverage (
  id             text primary key,
  schedule_id    text references schedules(id),
  trainer_id     text references trainers(id),
  course_id      text references courses(id),
  total_los      int default 0,
  covered_los    int default 0,
  coverage_notes text,
  date_submitted text
);

create table skill_gap_training (
  id                text primary key,
  trainee_name      text,
  skill_area        text,
  learning_outcomes text,
  duration_hours    int default 0,
  trainer_id        text references trainers(id),
  evidence_url      text,
  date              text
);

create table coop_followups (
  id                text primary key,
  trainee_id        text references trainees(id),
  trainee_name      text,
  organization_name text,
  visit_date        text,
  outcome           text,
  notes             text,
  status            text
);

create table coc_registrations (
  id                text primary key,
  trainee_id        text references trainees(id),
  trainee_name      text,
  department_id     text references departments(id),
  level             text,
  phone             text,
  amount_paid       real default 0,
  registration_date text,
  status            text
);

create table exam_approvals (
  id              text primary key,
  course_id       text references courses(id),
  trainer_id      text references trainers(id),
  exam_type       text check (exam_type in ('Theoretical','Practical')),
  status          text check (status in ('Draft','Pending','Approved')),
  submission_date text,
  approval_date   text,
  plan_details    text
);

create table assessment_results (
  id            text primary key,
  title         text not null,
  course_id     text references courses(id),
  level         text,
  section_code  text,
  avg_score     real,
  pass_rate     real,
  date_recorded text,
  status        text default 'Published'
);

create table trainer_evaluations (
  id         text primary key,
  trainer_id text references trainers(id),
  trainee    real,
  peer       real,
  self       real,
  department real,
  period     text
);

create table webinars (
  id           text primary key,
  title        text not null,
  host         text,
  start_time   text,
  duration_min int,
  registrants  int default 0,
  status       text,
  join_url     text
);

create table complaints (
  id        text primary key,
  subject   text not null,
  category  text,
  raised_by text,
  priority  text check (priority in ('Low','Medium','High')),
  status    text,
  date      text
);

create table audit_log (
  id         uuid primary key default gen_random_uuid(),
  entity     text,
  entity_id  text,
  action     text,
  actor      text,
  changes    jsonb,
  created_at timestamptz default now()
);

-- Helpful indexes
create index idx_schedule_trainer on schedules(trainer_id);
create index idx_attendance_sched on attendance(schedule_id);
create index idx_coverage_sched   on course_coverage(schedule_id);
create index idx_trainee_section  on trainees(section_code);
create index idx_audit_entity     on audit_log(entity, entity_id);


